import React, { useState } from 'react';
import { User, Mail, Lock, Save } from 'lucide-react';
import toast from 'react-hot-toast';
import { authApi } from '../services/api';
import { useAuth } from '../context/AuthContext';
import { getInitials, getErrorMessage } from '../utils/helpers';

export default function ProfilePage() {
  const { user, updateUser, logout } = useAuth();
  const [profile, setProfile] = useState({ name: user?.name || '', bio: user?.bio || '' });
  const [passwords, setPasswords] = useState({ currentPassword: '', newPassword: '', confirm: '' });
  const [savingProfile, setSavingProfile] = useState(false);
  const [savingPassword, setSavingPassword] = useState(false);

  const handleProfileSave = async (e) => {
    e.preventDefault();
    if (!profile.name.trim()) return toast.error('Name is required');
    setSavingProfile(true);
    try {
      const { data } = await authApi.updateMe(profile);
      updateUser(data.user);
      toast.success('Profile updated');
    } catch (err) { toast.error(getErrorMessage(err)); }
    finally { setSavingProfile(false); }
  };

  const handlePasswordChange = async (e) => {
    e.preventDefault();
    if (passwords.newPassword !== passwords.confirm) return toast.error('Passwords do not match');
    if (passwords.newPassword.length < 6) return toast.error('Password must be at least 6 characters');
    setSavingPassword(true);
    try {
      await authApi.changePassword({
        currentPassword: passwords.currentPassword,
        newPassword: passwords.newPassword,
      });
      toast.success('Password changed successfully');
      setPasswords({ currentPassword: '', newPassword: '', confirm: '' });
    } catch (err) { toast.error(getErrorMessage(err)); }
    finally { setSavingPassword(false); }
  };

  return (
    <div style={{ maxWidth: 600, margin: '0 auto' }}>
      <div className="page-header">
        <div>
          <h1>Profile</h1>
          <p style={{ color: 'var(--text-secondary)', fontSize: '0.875rem', marginTop: 4 }}>
            Manage your account settings
          </p>
        </div>
      </div>

      {/* Avatar + name hero */}
      <div className="card" style={{ marginBottom: '1.25rem', display: 'flex', alignItems: 'center', gap: '1.25rem' }}>
        <div className="avatar avatar-lg" style={{ width: 64, height: 64, fontSize: '1.4rem' }}>
          {getInitials(user?.name)}
        </div>
        <div>
          <h2 style={{ fontSize: '1.1rem', marginBottom: 2 }}>{user?.name}</h2>
          <p style={{ color: 'var(--text-secondary)', fontSize: '0.875rem' }}>{user?.email}</p>
        </div>
      </div>

      {/* Profile form */}
      <div className="card" style={{ marginBottom: '1.25rem' }}>
        <h3 style={{ fontSize: '0.95rem', marginBottom: '1.25rem', display: 'flex', alignItems: 'center', gap: 8 }}>
          <User size={16} style={{ color: 'var(--accent)' }} /> Personal Info
        </h3>
        <form onSubmit={handleProfileSave}>
          <div className="form-group">
            <label className="form-label">Full Name</label>
            <input
              className="input"
              value={profile.name}
              onChange={e => setProfile(p => ({ ...p, name: e.target.value }))}
              placeholder="Your full name"
            />
          </div>
          <div className="form-group">
            <label className="form-label">Email</label>
            <input
              className="input"
              value={user?.email}
              disabled
              style={{ opacity: 0.55, cursor: 'not-allowed' }}
            />
            <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>
              Email cannot be changed
            </span>
          </div>
          <div className="form-group">
            <label className="form-label">Bio</label>
            <textarea
              className="input"
              rows={3}
              value={profile.bio}
              onChange={e => setProfile(p => ({ ...p, bio: e.target.value }))}
              placeholder="A short bio about yourself"
            />
          </div>
          <div style={{ display: 'flex', justifyContent: 'flex-end' }}>
            <button type="submit" className="btn btn-primary" disabled={savingProfile}>
              {savingProfile ? <span className="spinner" /> : <><Save size={14} /> Save Changes</>}
            </button>
          </div>
        </form>
      </div>

      {/* Password form */}
      <div className="card" style={{ marginBottom: '1.25rem' }}>
        <h3 style={{ fontSize: '0.95rem', marginBottom: '1.25rem', display: 'flex', alignItems: 'center', gap: 8 }}>
          <Lock size={16} style={{ color: 'var(--accent)' }} /> Change Password
        </h3>
        <form onSubmit={handlePasswordChange}>
          {[
            { key: 'currentPassword', label: 'Current Password',  placeholder: '••••••••' },
            { key: 'newPassword',     label: 'New Password',      placeholder: '6+ characters' },
            { key: 'confirm',         label: 'Confirm Password',  placeholder: 'Repeat new password' },
          ].map(({ key, label, placeholder }) => (
            <div className="form-group" key={key}>
              <label className="form-label">{label}</label>
              <input
                className="input"
                type="password"
                placeholder={placeholder}
                value={passwords[key]}
                onChange={e => setPasswords(p => ({ ...p, [key]: e.target.value }))}
              />
            </div>
          ))}
          <div style={{ display: 'flex', justifyContent: 'flex-end' }}>
            <button type="submit" className="btn btn-primary" disabled={savingPassword}>
              {savingPassword ? <span className="spinner" /> : <><Lock size={14} /> Update Password</>}
            </button>
          </div>
        </form>
      </div>

      {/* Danger zone */}
      <div className="card" style={{ borderColor: '#3a1515' }}>
        <h3 style={{ fontSize: '0.95rem', marginBottom: '0.5rem', color: 'var(--red)' }}>
          Danger Zone
        </h3>
        <p style={{ fontSize: '0.85rem', color: 'var(--text-secondary)', marginBottom: '1rem' }}>
          Sign out of your account on this device.
        </p>
        <button className="btn btn-danger btn-sm" onClick={() => { logout(); }}>
          Sign Out
        </button>
      </div>
    </div>
  );
}
